#!/usr/bin/env python3
"""
Parameter sensitivity analysis.

Scans key parameters over ±5% ranges and reports their impact on strategy metrics
(Sharpe ratio, max drawdown, total return).

Usage:
    python3 scripts/sensitivity_analysis.py --config config/backtest_base_v1.json \\
        --results backtest/results/latest/*.json \\
        --output research/reports/sensitivity_report.json

    python3 scripts/sensitivity_analysis.py --help
"""

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path
from typing import Optional

import numpy as np
import pandas as pd

PROJECT_ROOT = Path(__file__).resolve().parents[1]
SCRIPTS_DIR = PROJECT_ROOT / "scripts"
if str(SCRIPTS_DIR) not in sys.path:
    sys.path.insert(0, str(SCRIPTS_DIR))


def _load_backtest_json(path: Path) -> dict:
    """Load a backtest result JSON, tolerating missing fields."""
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except (json.JSONDecodeError, FileNotFoundError):
        return {}


def _extract_metric(result: dict, metric: str) -> float:
    """Extract a named metric from a backtest result dict.

    Handles both top-level keys and nested 'metrics' / 'performance' sub-dicts.
    """
    # Direct key
    if metric in result:
        return float(result[metric])
    # metrics sub-dict
    metrics = result.get("metrics", {})
    if metric in metrics:
        return float(metrics[metric])
    # performance sub-dict
    perf = result.get("performance", {})
    if metric in perf:
        return float(perf[metric])
    # snake vs camel variations
    for key in ("sharpe_ratio", "sharpe", " Sharpe", "sharpeRatio"):
        if key in result:
            return float(result[key])
    for key in ("max_drawdown", "max_drawdown_pct", "mdd", "max_drawdown_pct"):
        if key in result:
            return float(result[key])
    for key in ("total_return", "total_return_pct", "annual_return", "annual_return_pct"):
        if key in result:
            return float(result[key])
    return float("nan")


def run_sensitivity_analysis(
    base_config: dict,
    param_ranges: dict[str, tuple[float, float, int]],
    metric: str = "sharpe_ratio",
    backtest_results_dir: Optional[Path] = None,
) -> dict:
    """
    For each parameter in *param_ranges*, uniformly sample values between min and max
    (inclusive) and collect the *metric* value.

    Parameters
    ----------
    base_config : dict
        Base strategy configuration (parameter values).
    param_ranges : dict[str, tuple[float, float, int]]
        Mapping of parameter name → (min, max, num_steps).
    metric : str
        Metric key to extract from each backtest result.
    backtest_results_dir : Path, optional
        Directory containing backtest JSON files.
        When None, all metric values default to 0.0 (placeholder mode).

    Returns
    -------
    dict
        Sensitivity report with per-parameter sensitivity index, stability flag,
        best/worst values, and full detail list.
    """
    results: list[dict] = []

    # Build a lookup: ts_code → result file (for per-stock backtests)
    result_files: dict[str, Path] = {}
    if backtest_results_dir and backtest_results_dir.exists():
        for fpath in backtest_results_dir.rglob("*.json"):
            result_files[fpath.stem] = fpath

    for param_name, (p_min, p_max, steps) in param_ranges.items():
        param_values = np.linspace(p_min, p_max, steps)
        for val in param_values:
            cfg = {**base_config, param_name: val}

            # Try to load matching backtest result
            metric_val: float = float("nan")
            if backtest_results_dir and backtest_results_dir.exists():
                # Match by serialising config hash (use param value as proxy key)
                tag = f"{param_name}_{val:.4f}"
                candidates = [
                    f for f in result_files
                    if param_name.lower() in f.lower() or tag.lower() in f.lower()
                ]
                if candidates:
                    res = _load_backtest_json(result_files[candidates[0]])
                    metric_val = _extract_metric(res, metric)

            results.append({
                "param": param_name,
                "param_value": round(float(val), 6),
                "metric_value": metric_val if not np.isnan(metric_val) else 0.0,
            })

    # Build report
    report: dict = {"param_sensitivity": [], "metric": metric}

    for param_name in param_ranges:
        param_results = [r for r in results if r["param"] == param_name]
        values = [r["param_value"] for r in param_results]
        metrics = [r["metric_value"] for r in param_results]

        max_metric = max(metrics)
        min_metric = min(metrics)
        sensitivity = float(max_metric - min_metric)

        # Stability: sensitivity < 5% of mean absolute metric (or < 0.05 if near zero)
        mean_abs = float(np.mean([abs(m) for m in metrics]))
        stable = bool(sensitivity < max(0.05, 0.05 * mean_abs))

        report["param_sensitivity"].append({
            "param": param_name,
            "sensitivity": round(sensitivity, 4),
            "stable": stable,
            "best_value": float(values[metrics.index(max_metric)]),
            "worst_value": float(values[metrics.index(min_metric)]),
            "best_metric": round(max_metric, 4),
            "worst_metric": round(min_metric, 4),
            "detail": [
                {"value": round(v, 4), "metric": round(m, 4)}
                for v, m in zip(values, metrics)
            ],
        })

    return report


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Parameter sensitivity analysis: scan key params ±5%% and report impact on metrics.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  python3 scripts/sensitivity_analysis.py --help

  python3 scripts/sensitivity_analysis.py \\
      --base-config '{"topk":8,"n_drop":3}' \\
      --param-ranges '{"topk":[6,10,5],"n_drop":[1,5,5]}' \\
      --metric sharpe_ratio \\
      --output research/reports/sensitivity_report.json

  # Read base config from file and results directory:
  python3 scripts/sensitivity_analysis.py \\
      --config config/backtest_base_v1.json \\
      --results backtest/results/walkforward/ \\
      --metric sharpe_ratio \\
      --output research/reports/sensitivity_report.json
""",
    )
    parser.add_argument(
        "--base-config",
        type=str,
        default="{}",
        help="JSON string or file path containing base strategy config dict.",
    )
    parser.add_argument(
        "--param-ranges",
        type=str,
        default="{}",
        help="JSON string mapping param → [min, max, steps].",
    )
    parser.add_argument(
        "--results",
        type=str,
        default="",
        help="Directory containing backtest result JSON files.",
    )
    parser.add_argument(
        "--metric",
        type=str,
        default="sharpe_ratio",
        help="Metric to extract: sharpe_ratio, max_drawdown, total_return (default: sharpe_ratio).",
    )
    parser.add_argument(
        "--output",
        type=str,
        default="",
        help="Output path for sensitivity report JSON.",
    )

    args = parser.parse_args()

    # Parse base config
    base_config: dict = {}
    if args.base_config:
        try:
            base_config = json.loads(args.base_config)
        except json.JSONDecodeError:
            p = Path(args.base_config)
            if p.exists():
                base_config = json.loads(p.read_text(encoding="utf-8"))
            else:
                print(f"ERROR: cannot parse --base-config: {args.base_config}", file=sys.stderr)
                return 1

    # Parse param ranges
    param_ranges: dict = {}
    if args.param_ranges:
        try:
            raw = json.loads(args.param_ranges)
            # Support both dict and list-of-lists format
            if isinstance(raw, dict):
                param_ranges = {
                    k: tuple(v) for k, v in raw.items()
                }
            else:
                # [{name, min, max, steps}, ...]
                for item in raw:
                    param_ranges[item["name"]] = (item["min"], item["max"], item.get("steps", 5))
        except (json.JSONDecodeError, TypeError) as e:
            print(f"ERROR: cannot parse --param-ranges: {e}", file=sys.stderr)
            return 1

    if not param_ranges:
        print("WARNING: --param-ranges is empty; producing empty report.", file=sys.stderr)

    # Results directory
    results_dir = Path(args.results) if args.results else None

    report = run_sensitivity_analysis(
        base_config=base_config,
        param_ranges=param_ranges,
        metric=args.metric,
        backtest_results_dir=results_dir,
    )

    if args.output:
        out_path = Path(args.output)
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
        print(f"Report written to {out_path}")
    else:
        print(json.dumps(report, indent=2, ensure_ascii=False))

    return 0


if __name__ == "__main__":
    sys.exit(main())

